import { type HTMLAttributes, forwardRef } from "react";
import { clsx } from "clsx";
import { Slot } from "@radix-ui/react-slot";
import * as styles from "./List.css";
import { type ListVariant, DEFAULT_LIST_VARIANT } from "./List.config";

export const LIST_VARIANT_CLASSES = {
  border: styles.BORDER_VARIANT_CLASS,
  default: styles.DEFAULT_VARIANT_CLASS,
};

interface ListCustomProps {
  /**
   * The visual variant of the list container.
   * - `default`: White background with dividers between items
   * - `border`: Bordered container with rounded corners
   * @default 'default'
   */
  variant?: ListVariant;

  /**
   * When true, the component will render its child element instead of the default
   * `<ul>` element, merging the List's props and behavior onto the child.
   *
   * Use this to render an `<ol>` for ordered lists while maintaining List styling.
   *
   * @example
   * ```tsx
   * <List asChild variant="border">
   *   <ol>
   *     <ListItem>First item</ListItem>
   *     <ListItem>Second item</ListItem>
   *   </ol>
   * </List>
   * ```
   */
  asChild?: boolean;
}

export interface ListProps
  extends
    Omit<HTMLAttributes<HTMLUListElement>, keyof ListCustomProps>,
    ListCustomProps {}

/**
 * A list container component that renders a semantic `<ul>` element by default.
 *
 * Use with `ListItem`, `ListItemAction`, and `ListItemDivider` components
 * to create styled lists with different visual variants.
 *
 * For ordered lists, use the `asChild` prop with an `<ol>` child element.
 *
 * Accessibility (WCAG 2.1 AA):
 * - Uses semantic list elements (`<ul>` or `<ol>`) for proper screen reader announcements
 * - List items are announced with their position (e.g., "item 1 of 3")
 * - Supports keyboard navigation when list items contain interactive elements
 */
export const List = forwardRef<HTMLUListElement, ListProps>(
  (
    {
      children,
      className,
      variant = DEFAULT_LIST_VARIANT,
      asChild = false,
      ...props
    },
    ref
  ) => {
    const Component = asChild ? Slot : "ul";

    return (
      <Component
        ref={ref}
        className={clsx(styles.list({ variant }), className)}
        {...props}
      >
        {children}
      </Component>
    );
  }
);

List.displayName = "List";
